+fn apply_queue_modes_updates_injected_queue_delivery_policy() {
+    let app = build_test_app_with_config(Config {
+        steering_mode: Some("one-at-a-time".to_string()),
+        follow_up_mode: Some("one-at-a-time".to_string()),
